parameters.jsCode:
function parseModelResult(value) {
  const raw = String(value ?? '').trim();

  const cleaned = raw
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();

  try {
    return {
      parsed: true,
      data: JSON.parse(cleaned),
      raw,
    };
  } catch {
    return {
      parsed: false,
      data: {},
      raw,
    };
  }
}

const glmInput =
  $('GLM-Ergebnis vorbereiten').item.json;

const glm =
  parseModelResult(glmInput.glm_raw);

const qwen =
  parseModelResult($json.message?.content);

return {
  json: {
    document_id:
      glmInput.document_id,

    title:
      glmInput.title,

    original_file_name:
      glmInput.original_file_name,

    // Ursprünglichen Paperless-OCR-Text behalten.
    original_content:
      glmInput.original_content,

    original_custom_fields:
      glmInput.original_custom_fields,

    page_number:
      glmInput.page_number,

    page_file_name:
      glmInput.page_file_name,

    glm_parsed:
      glm.parsed,

    glm:
      glm.data,

    glm_raw:
      glm.raw,

    qwen_parsed:
      qwen.parsed,

    qwen:
      qwen.data,

    qwen_raw:
      qwen.raw,
  },
};

const pages = $input
  .all()
  .map(item => item.json)
  .sort(
    (a, b) =>
      Number(a.page_number) -
      Number(b.page_number)
  );

function toArray(value) {
  return Array.isArray(value)
    ? value.filter(value =>
        value !== null &&
        value !== undefined &&
        String(value).trim() !== ''
      )
    : [];
}

/**
 * Falls der Workflow dasselbe Dokument erneut verarbeitet,
 * wird nur der wirklich ursprüngliche Paperless-OCR-Bereich
 * übernommen.
 */
function extractOriginalPaperlessContent(content) {
  const value =
    String(content ?? '').trim();

  const marker =
    '=== Ursprünglicher Paperless-OCR-Inhalt ===';

  if (!value.includes(marker)) {
    return value;
  }

  return value
    .split(marker)
    .slice(1)
    .join(marker)
    .trim();
}

const textParts = [];
const tables = [];
const documentStructures = [];
const imageDescriptions = [];
const warnings = [];

for (const page of pages) {
  const glmText =
    page.glm?.text_markdown ||
    page.glm?.text ||
    (!page.glm_parsed
      ? page.glm_raw
      : '');

  if (String(glmText ?? '').trim()) {
    textParts.push(
      `## Seite ${page.page_number}\n\n` +
      String(glmText).trim()
    );
  }

  for (
    const table of toArray(
      page.glm?.tables_markdown
    )
  ) {
    tables.push(
      `### Tabelle auf Seite ${page.page_number}\n\n` +
      String(table).trim()
    );
  }

  const structures =
    toArray(
      page.glm?.document_structure
    );

  if (structures.length > 0) {
    documentStructures.push(
      `### Struktur auf Seite ${page.page_number}\n\n` +
      structures
        .map(value => `- ${value}`)
        .join('\n')
    );
  }

  const visualParts = [
    ...toArray(page.qwen?.symbols),
    ...toArray(page.qwen?.stamps),
    ...toArray(page.qwen?.signatures),
    ...toArray(page.qwen?.handwriting),
    ...toArray(page.qwen?.images),
    ...toArray(page.qwen?.visual_notes),
  ];

  if (visualParts.length > 0) {
    imageDescriptions.push(
      `### Visuelle Inhalte auf Seite ${page.page_number}\n\n` +
      visualParts
        .map(value => `- ${value}`)
        .join('\n')
    );
  }

  warnings.push(
    ...toArray(page.glm?.warnings),
    ...toArray(page.qwen?.warnings)
  );
}

const aiSections = [];

if (textParts.length > 0) {
  aiSections.push(
    `# Dokumenttext\n\n${textParts.join('\n\n')}`
  );
}

if (tables.length > 0) {
  aiSections.push(
    `# Tabellen\n\n${tables.join('\n\n')}`
  );
}

if (documentStructures.length > 0) {
  aiSections.push(
    `# Dokumentstruktur\n\n` +
    documentStructures.join('\n\n')
  );
}

if (imageDescriptions.length > 0) {
  aiSections.push(
    `# Bild- und Layouterkennung\n\n` +
    imageDescriptions.join('\n\n')
  );
}

// Ausschließlich neu erzeugter KI-/Vision-Inhalt.
const aiContent =
  aiSections.join('\n\n').trim();

// Wirklich ursprünglicher Paperless-OCR-Inhalt.
const originalPaperlessContent =
  extractOriginalPaperlessContent(
    pages[0]?.original_content
  );

const originalSection =
  originalPaperlessContent ||
  '[Kein ursprünglicher Paperless-OCR-Inhalt vorhanden]';

// Dieser Inhalt wird später nach Paperless geschrieben.
const combinedPaperlessContent = [
  '=== KI-OCR / Vision-Ergebnis ===',
  '',
  aiContent ||
    '[Kein brauchbares KI-OCR-Ergebnis erzeugt]',
  '',
  '=== Ursprünglicher Paperless-OCR-Inhalt ===',
  '',
  originalSection,
]
  .join('\n')
  .trim();

/**
 * Qualitätsprüfung ausschließlich auf Grundlage
 * des neuen KI-Inhalts.
 */
const normalizedAiContent =
  aiContent.toLowerCase();

const contentWithoutErrorPhrases =
  normalizedAiContent
    .replace(/\[?unlesbar\]?/gi, '')
    .replace(/keine daten/gi, '')
    .replace(/nicht erkennbar/gi, '')
    .replace(/kein text erkannt/gi, '')
    .replace(/^#+.*$/gm, '')
    .replace(/\s+/g, '');

const quality = {
  usable:
    pages.length > 0 &&
    aiContent.length >= 100 &&
    contentWithoutErrorPhrases.length >= 30,

  ai_character_count:
    aiContent.length,

  original_character_count:
    originalPaperlessContent.length,

  combined_character_count:
    combinedPaperlessContent.length,

  page_count:
    pages.length,

  glm_json_valid_for_all_pages:
    pages.every(page =>
      page.glm_parsed === true
    ),

  qwen_json_valid_for_all_pages:
    pages.every(page =>
      page.qwen_parsed === true
    ),

  markdown_table_detected:
    tables.length > 0,

  image_descriptions_present:
    imageDescriptions.length > 0,

  warnings,
};

return [
  {
    json: {
      document_id:
        pages[0]?.document_id,

      title:
        pages[0]?.title ?? '',

      original_file_name:
        pages[0]?.original_file_name ?? '',

      original_custom_fields:
        pages[0]?.original_custom_fields ?? [],

      pages,

      ai_content:
        aiContent,

      original_paperless_content:
        originalPaperlessContent,

      combined_paperless_content:
        combinedPaperlessContent,

      quality,

      // Während der Tests nicht nach Paperless schreiben.
      write_back: false,
    },
  },
];

